mapper.update:
update room
set status = -1, recycletime = NOW()
where roomid = #{roomid}

update room
set status = 0, recycletime = NULL
where roomid = #{roomid}

mapper.select:
select roomname, roomid, onerid, status, time
from room
where status = -1 and onerid = #{onerid}

select count(*)
from room
where status = -1 and onerid = #{onerid}

select roomname, roomid, onerid, status, time
from room
where status = -1 and onerid = #{onerid}
order by recycletime desc
limit #{offset}, #{pageSize}

select *
from room
where status = -1 and recycletime < #{dateTime}

select roomname, roomid, onerid, status, time
from room
where status != -1
and onerid = #{onerid}
order by time desc
limit #{offset}, #{pageSize}

